module top_module(clk,resetn,d,squashn,en,q);input clk;
input resetn;
input en;
input squashn;
input [31:0] d;
output [31:0] q;
reg [31:0] q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)   //synchronous reset
begin
  if (resetn==0 || squashn==0)
    q<=0;
  else if (en==1)
   begin
    q[4:0]<=d;
	q[31:5] <= 0;

	end
end

endmodule
